return-response.set-body:
@{
              var a = (Newtonsoft.Json.Linq.JObject)context.Variables["auth"];
              var o = new Newtonsoft.Json.Linq.JObject();
              o["decision"] = "DENY_AUTHZ";
              o["reason"] = "Authenticated client is not authorised for path B (client2)";
              o["authenticatedClient"] = (string)a["client"];
              o["requiredClient"] = "client2";
              o["presentedThumbprint"] = (string)a["thumbprint"];
              return o.ToString();
          }

@{
          var a = (Newtonsoft.Json.Linq.JObject)context.Variables["auth"];
          var o = new Newtonsoft.Json.Linq.JObject();
          o["decision"] = "ALLOW";
          o["client"] = "client2";
          o["path"] = "B";
          o["message"] = "Hello client2 - authenticated by client certificate and authorised for path B";
          o["presentedThumbprint"] = (string)a["thumbprint"];
          o["mode"] = (string)a["mode"];
          o["appGwVerify"] = (string)a["appGwVerify"];
          o["chainOk"] = (bool)a["chainOk"];
          return o.ToString();
      }
